@st.cache_data
def load_models():
    """Load pre-trained model data.
    First tries local models/ folder (for local dev), then falls
    back to the inline data embedded in this file (for Streamlit Cloud).
    """
    base = Path(__file__).parent / "models"
    models = {}
    names = ["mse", "perceptron", "backprop", "rnn", "lstm", "cnn"]
    for n in names:
        path = base / f"out_{n}.json"
        if path.exists():
            with open(path) as f:
                models[n] = json.load(f)
        else:
            # Fall back to inline data
            models[n] = _INLINE_DATA.get(n)
    return models

DATA = load_models()


